#!/usr/bin/env python3
# Vendor Suit -- Phase 6-C(i): invoice LIST read-flip to the engine.
# GET /api/v2/vendor/invoices/:vendorId now reads money-IN binders from
# engine.records (direction 'in'); state is DERIVED from the money figures.
# invoice_number + due_date deferred to "generate invoice". Adds resolveAgent().
# Writes (create/payment/cancel/update) are 6-C(ii). Guarded + idempotent.
#   unzip -o vendor-suit-phase6ci-invoices-read-v1.zip && python3 writer.py
import os, sys, base64, json
ROOT = os.getcwd()
def die(m): print("ABORT: " + m); sys.exit(1)
if not os.path.isfile("package.json") or json.load(open("package.json")).get("name") != "dream-os-backend":
    die("run from the dream-os repo root.")
F = os.path.join(ROOT, "src", "api", "vendor", "invoices.js")
if not os.path.isfile(F): die("invoices.js not found.")
P = {'old': '', 'new': ''}
old = base64.b64decode(P["old"]).decode(); new = base64.b64decode(P["new"]).decode()
txt = open(F, encoding="utf-8").read()
if "6-C(i) — invoices read Harvey/Donna" in txt:
    print("= invoice list already flipped (idempotent)."); sys.exit(0)
if "resolveAgent" not in txt:
    anchor = "const resolveVendor  = require('../middleware/resolveVendor');"
    if anchor not in txt: die("resolveVendor anchor not found -- inspect.")
    txt = txt.replace(anchor, anchor + "\nconst resolveAgent   = require('../middleware/resolveAgent');", 1)
    print("+ invoices.js: added resolveAgent require")
if old not in txt: die("invoice GET handler not found verbatim -- inspect.")
txt = txt.replace(old, new, 1)
print("+ invoices.js: GET list re-pointed public.invoices -> engine.records (direction in)")
open(F, "w", encoding="utf-8").write(txt)
print("\nDone. Restart; GET /vendor/invoices reads the engine ledger.")
